      function CF_5Formula return char is
V_DISPLAY CHAR(30);


v_ins_id VARCHAR2(1);
 
Cursor cur_ins_id is 
SELECT SEX
FROM REG_INSURED 
WHERE INSURED_ID = :P_INSURED_ID;

begin


      OPEN cur_ins_id;
      FETCH cur_ins_id
      INTO v_ins_id;
      CLOSE cur_ins_id;


  
IF v_ins_id='Α' THEN
	V_DISPLAY:='στον ασφαλισμένο με στοιχεία:';
end if;
IF v_ins_id='Θ' THEN
	V_DISPLAY:='στην ασφαλισμένη με στοιχεία:';
end if;

return v_display;
end;

