      function CF_7Formula return Char is
v_calc_begin_date_varchar varchar2(10);
v_calc_begin_date date;
V_AMOUNT NUMBER;

begin

      v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
                     0,:p_form_id,'00001','00318','00420');
        IF v_calc_begin_date_varchar IS NOT NULL THEN
           v_calc_begin_date := TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR');
        END IF;


    V_AMOUNT := Penbat_Payments.Calc_Total_Scale_Raise_Back (NULL
                                                         ,NULL
                                                         ,v_calc_begin_date
                                                          ,:P_ACC_START_DATE
                                                         ,:P_PENSION_AMOUNT);
  
  RETURN (ROUND(V_AMOUNT,2)+:P_PENSION_AMOUNT); 
  
  
end;

      function CF_8Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
/*CURSOR CUR IS
SELECT ADAPODOTIKH_AMT
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO; 
*/
CURSOR CUR_1 IS
SELECT  FINAL_NAT_PENSION_AMT
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


begin
  
 /* OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  */
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  
  RETURN NVL(V_NUM_1,0);
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_9Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  
  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

