function CF_13Formula return CHAR is CURSOR CUR_INITIAL_REQUEST IS SELECT C.APPL_PROTOCOL_NO||'/'||TO_CHAR(C.START_DATE) FROM WRK_IN_OUT A, WRK_IN_OUT B, WRK_APPLICATION C WHERE A.PROTOCOL_NO = :P_APPL_INCR_SEQ_NO AND A.PROTOCOL_YEAR = :P_APPL_YEAR AND A.PROTOCOL_ORGBRA_CODE = :P_APPL_UNIT_CODE AND A.STATUS = '1' AND A.TYPE_FLG = '1' AND A.RECEIVE_APPL_FLG = '1' AND A.DOCUMENT_CODE = '022' AND B.PROTOCOL_NO = A.PROTOCOL_NO_AYE AND B.PROTOCOL_YEAR = A.PROTOCOL_YEAR_AYE AND B.PROTOCOL_ORGBRA_CODE = A.PROTOCOL_ORGBRA_CODE_AYE AND B.STATUS = '1' AND B.DOCUMENT_CODE = '001' AND B.TYPE_FLG = '1' AND B.RECEIVE_APPL_FLG = '1' AND B.REF_APPL_SID = C.APPL_SID AND C.STATUS = '1';
V_INITIAL_PROTOCOL WRK_IN_OUT.PROTOCOL_NO_AYE%TYPE;
begin
OPEN CUR_INITIAL_REQUEST; FETCH CUR_INITIAL_REQUEST INTO V_INITIAL_PROTOCOL; CLOSE CUR_INITIAL_REQUEST;
RETURN V_INITIAL_PROTOCOL;
end;

      function CF_ANNOUNCEMENTFormula return Char is

V_BRANCH_CODE VARCHAR2(5);
V_BRANCH_NAME VARCHAR2(50);

BEGIN
  V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00172','00247');
  IF V_BRANCH_CODE IS NULL THEN
  	V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00069','00247');			 
  END IF;
  
  IF V_BRANCH_CODE IS NULL THEN
	    V_BRANCH_CODE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
				 0,0,'00001','01069','00247');   
		END IF;		 
  
IF V_BRANCH_CODE IS NOT NULL THEN
     SELECT A.BRANCH_NAME
	   INTO V_BRANCH_NAME
	   FROM COM_ORG_BRANCHES A
	   WHERE A.BRANCH_CODE = V_BRANCH_CODE;
ELSE
	V_BRANCH_NAME:= ' ';
END IF;

RETURN V_BRANCH_NAME;
END;

      function CF_soixeia_paymentsFormula return Char is

to_return varchar2(500);
v_iban      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='01069' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_INSURED_ID AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code = '00111';
  
cursor Cur_Fact_Subtype_Existance_2 IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='01069' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_INSURED_ID AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code = '00584';

V_DEATH_REASON VARCHAR2(20);
begin
	to_return :='';
	v_iban:=null;
	   open Cur_Fact_Subtype_Existance;
     fetch Cur_Fact_Subtype_Existance into v_iban;
     close Cur_Fact_Subtype_Existance; 
     open Cur_Fact_Subtype_Existance_2;
     fetch Cur_Fact_Subtype_Existance_2 into V_DEATH_REASON;
     close Cur_Fact_Subtype_Existance_2;                                              
    if v_iban is not null then
    	IF V_DEATH_REASON='1' THEN
    		to_Return:='Πληρωμή Σύνταξης χωρίς πίστωση σε Τραπεζικό Λογαριασμό.';
    	ELSE	
    	 to_Return:='Πληρωμή Σύνταξης με πίστωση σε Τραπεζικό Λογαριασμό.';
    	END IF; 
    end if;
   return to_Return;
end;

