      function CF_DEBT_DESCRFormula return Char is
TO_RETURN VARCHAR2(1000);

CURSOR C1 IS
 SELECT PRCN_DESCR
   FROM PPI_PEN_DEBTS_PRCN
  WHERE PRCN= :DEDUCTION_PENSION_FACTOR;
V_PRCN_DESCR VARCHAR2(200);  
begin
	
  if :debt_id in ('31') then
  	to_return:=:num_debt||'. Συμψηφίζεται '||:descr||' Συνολικού Ποσού: '||:TOTAL_DEDUCTION_AMMOUNT||' ΕΥΡΩ';
  elsif :debt_id ='121' then 
  	to_return:=:num_debt||'. Συμψηφίζονται '||:descr||' Συνολικού Ποσού: '||:TOTAL_DEDUCTION_AMMOUNT||' ΕΥΡΩ';
  else
  	OPEN C1;
  	FETCH C1 INTO V_PRCN_DESCR;
  	CLOSE C1;
  	to_return:='Παρακράτηση ';
  	if :DOSAGE_AMOUNT is not null then 
  			to_return:=:num_debt||'. '||to_return||' ποσού '||:DOSAGE_AMOUNT||' ΕΥΡΩ '||' της μηνιαίας Σύνταξης ';
  	else
  			to_return:=:num_debt||'. '||to_return||' ποσοστού '||V_PRCN_DESCR||' της μηνιαίας Σύνταξης ';
  	end if;		
  		to_return:=to_return||' για '||:descr||' από Συνολικό Ποσό: '||:TOTAL_DEDUCTION_AMMOUNT||' ΕΥΡΩ';
  end if;	
  return TO_RETURN;
end;

      function CF_51Formula return Char is
v_char VARCHAR2(10);
v_char_descr VARCHAR2(200);

CURSOR CUR IS
SELECT PERCENTAGE||'% '--DESCR||' : '||PERCENTAGE||' % '
FROM PEN_SICKNESS_DEDUCTIONS_NEW
WHERE SICKNESS_DEDUCTION_ID= v_char
AND EFFECTIVE_DATE <= SYSDATE--NVL(:P_FACTITIOUS_DATE, SYSDATE)
ORDER BY EFFECTIVE_DATE DESC;

begin
  /* CHRYS 10/1/2018 v_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR_DIR,
                                             :P_DT_DEC_UNIT_CODE_DIR,
                                             :P_DT_INCR_SEC_NO_DIR, 
                                             '1',
                                                   0,
                                                    0,
                                                   '00001',
                                                   '01069',
                                                   '00674');
                                                   
 /* CHRYS 10/1/2018 */                                                 
     v_char := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                             :P_DT_DECISION_YEAR,
                                             :P_DT_DEC_UNIT_CODE,
                                             :P_DEC_INCR_SEC_NO_SR, 
                                             '1',
                                               0,
                                               0,
                                               '00001',
                                               '01069',
                                               '00228');
   
  OPEN CUR;
  FETCH CUR 
  INTO v_char_descr;
  CLOSE CUR;
                    
       IF v_char_descr IS NULL THEN
       	v_char_descr := '6% ';
       END IF;
       RETURN  v_char_descr ;                                   
end;

