      FUNCTION CF_PERSON_NAMEFormula RETURN CHAR IS

 v_Psv_user_id VARCHAR2(15);
 V_PERSON_NAME VARCHAR2(100);

Cursor cur_Psv_user_id is 
SELECT Created_By
FROM PEN_DECISION_INSTANCE
WHERE  PEN_DECISION_INSTANCE.Dec_Incr_Seq_No=:P_Dec_Incr_SeC_No
AND PEN_DECISION_INSTANCE.Dt_Dec_Unit_Code=:P_Dt_Dec_Unit_Code
AND PEN_DECISION_INSTANCE.Dt_Decision_Year=:P_Dt_Decision_Year
AND PEN_DECISION_INSTANCE.Dt_Document_Type_Dec_Code='1';

begin
   --Psv_User_Id    := Sec_Appl_Pkg.Get_Current_User(:P_Login_Id);
   
   	OPEN cur_Psv_user_id;
	  FETCH cur_Psv_user_id
	  INTO v_Psv_user_id;
	  CLOSE cur_Psv_user_id;

   SELECT PERSON_SURNAME || ' ' ||PERSON_NAME
   INTO V_PERSON_NAME
   FROM SEC_USERS  
   WHERE USER_ID = v_Psv_user_id;

   RETURN V_PERSON_NAME; 
end;

      function CF_ACC_END_DATEFormula return Date is

V_END_DATE                      DATE;
V_DOCUMENT_TYPE_DEC_CODE_SR     PEN_DECISION_INSTANCE.DOCUMENT_TYPE_DEC_CODE_SR%TYPE;
V_DEC_UNIT_CODE_SR							PEN_DECISION_INSTANCE.DEC_UNIT_CODE_SR%TYPE;
V_DECISION_YEAR_SR							PEN_DECISION_INSTANCE.DECISION_YEAR_SR%TYPE;
V_INCR_SEQ_NO_SR								PEN_DECISION_INSTANCE.INCR_SEQ_NO_SR%TYPE;
V_DECISION_STATE_FLG						PEN_DECISION_INSTANCE.DECISION_STATE_FLG%TYPE;
V_USAGE_FLG											VARCHAR2(1);
V_TMP_FLG                       VARCHAR2(1);

Cursor CUR_PEN_DEC_INST is
SELECT DOCUMENT_TYPE_DEC_CODE_SR, DEC_UNIT_CODE_SR, DECISION_YEAR_SR, INCR_SEQ_NO_SR, DECISION_STATE_FLG
FROM  PEN_DECISION_INSTANCE
WHERE PEN_DECISION_INSTANCE.Dec_Incr_Seq_No           =:P_Dec_Incr_SeC_No
 AND  PEN_DECISION_INSTANCE.Dt_Dec_Unit_Code          =:P_Dt_Dec_Unit_Code
 AND  PEN_DECISION_INSTANCE.Dt_Decision_Year          =:P_Dt_Decision_Year
 AND  PEN_DECISION_INSTANCE.Dt_Document_Type_Dec_Code ='1';


Cursor CUR_DATE(P_DOCUMENT_TYPE_DEC_CODE_SR IN VARCHAR2,
								P_DEC_UNIT_CODE_SR 					IN VARCHAR2,
								P_DECISION_YEAR_SR					IN NUMBER,
								P_INCR_SEQ_NO_SR            IN NUMBER,
								P_USAGE_FLG                 IN VARCHAR2,
								P_TMP_FLG                   IN VARCHAR2) is 
SELECT END_DATE
FROM  PEN_ACCOUNT
WHERE DI_DT_DOCUMENT_TYPE_DEC_CODE = P_DOCUMENT_TYPE_DEC_CODE_SR 
 AND  DI_DT_DEC_UNIT_CODE          = P_DEC_UNIT_CODE_SR 
 AND  DI_DT_DECISION_YEAR          = P_DECISION_YEAR_SR 
 AND  DI_DEC_INCR_SEQ_NO           = P_INCR_SEQ_NO_SR 
 AND  USAGE_FLG                    = P_USAGE_FLG 
 AND  TEMP_FLG                     = P_TMP_FLG 
 ;

begin
	  OPEN CUR_PEN_DEC_INST;
	   FETCH CUR_PEN_DEC_INST INTO V_DOCUMENT_TYPE_DEC_CODE_SR, V_DEC_UNIT_CODE_SR, V_DECISION_YEAR_SR, V_INCR_SEQ_NO_SR, V_DECISION_STATE_FLG;
	  CLOSE CUR_PEN_DEC_INST; 
	
		IF V_DECISION_STATE_FLG='1' THEN
			V_USAGE_FLG:='1';
		  V_TMP_FLG  :='0';
		ELSE
			V_USAGE_FLG:='1';
		  V_TMP_FLG  :='1';
		END IF;
   
   OPEN CUR_DATE (V_DOCUMENT_TYPE_DEC_CODE_SR, V_DEC_UNIT_CODE_SR, V_DECISION_YEAR_SR, V_INCR_SEQ_NO_SR, V_USAGE_FLG, V_TMP_FLG);
	  FETCH CUR_DATE INTO V_END_DATE;
	 CLOSE CUR_DATE;

   RETURN V_END_DATE; 
   EXCEPTION WHEN OTHERS THEN RETURN NULL;
	
end;

