      function B_61FormatTrigger return boolean is
v_product        varchar2(5);

cursor cur_product is
  SELECT PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
  FROM PEN_QC_PER_PRODINST, 
       PEN_PRODUCT_PER_INSTITUTIONS
 WHERE PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST
   AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE;



begin
    
    open cur_product;
    fetch cur_product
    into v_product;
    close cur_product;
    
   
    
  if v_product = '00001' then
      return (true);
  else
      return (FALSE);
  end if;
end;

